(function(factory){
  if (typeof define === 'function' && define.amd) {
    define(['jquery'], factory);
  } else {
    factory(window.jQuery);
  }
})(function($){
  if (!$) return;

  $.fn.owlCarousel = function(options) {
    return this.each(function() {
      $(this).addClass('owl-loaded').data('owl.carousel', {
        options: options || {}
      });
    });
  };
});
